const body = $json.body ?? $json;
const sales = Number(body.sales ?? 0);
const labor = Number(body.labor ?? 0);
const waste = Number(body.waste ?? 0);
const incidents = Array.isArray(body.incidents) ? body.incidents : [];
const laborPct = sales > 0 ? Math.round((labor / sales) * 1000) / 10 : null;
const wastePct = sales > 0 ? Math.round((waste / sales) * 1000) / 10 : null;
const flags = [];
if (laborPct !== null && laborPct > 30) flags.push('labor_above_target');
if (wastePct !== null && wastePct > 3) flags.push('waste_above_target');
if (incidents.length) flags.push('incident_review_needed');
return [{
  json: {
    workflow: 'qsr-daily-store-ops-digest',
    storeId: body.storeId ?? 'unknown',
    businessDate: body.businessDate ?? new Date().toISOString().slice(0, 10),
    metrics: {
      sales,
      labor,
      laborPct,
      waste,
      wastePct,
      tickets: Number(body.tickets ?? 0),
      avgTicket: Number(body.tickets ?? 0) ? Math.round((sales / Number(body.tickets)) * 100) / 100 : null
    },
    incidents,
    flags,
    managerDigest: flags.length ? 'Review flagged labor, waste, or incident items before opening tomorrow.' : 'No major exceptions detected from submitted metrics.',
    nextStep: flags.length ? 'send_to_manager_and_district_queue' : 'archive_daily_digest'
  }
}];
